code.C:
#include <stdio.h>
#include <math.h>
int main() {
    int k, n;
    scanf("%d %d", &k, &n);
    printf("%d\n", (int)ceil((double)n / k));
    return 0;
}

code.C++:
#include <iostream>
#include <cmath>
using namespace std;
int main() {
    int k, n;
    cin >> k >> n;
    cout << (int)ceil((double)n / k) << endl;
    return 0;
}

code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int k = scanner.nextInt();
        int n = scanner.nextInt();
        System.out.println((int)Math.ceil((double)n / k));
    }
}

code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
rl.on('line', (input) => {
    const [k, n] = input.split(' ').map(Number);
    console.log(Math.ceil(n / k));
});

